query:
-- Fix Pç and Pc. to Praça
UPDATE establishments SET address = CONCAT('Praça', SUBSTRING(address, 3)) WHERE address LIKE 'Pç %' OR address LIKE 'Pç.%';
UPDATE establishments SET address = CONCAT('Praça', SUBSTRING(address, 4)) WHERE address LIKE 'Pc.%' OR address LIKE 'Pc %';

-- Fix "BELA VISTA - Praça..." pattern
UPDATE establishments SET address = SUBSTRING(address, LOCATE('Praça', address)) WHERE address LIKE '%- Praça%' AND address NOT REGEXP '^(Rua|Avenida|Alameda|Praça|Travessa|Largo|Estrada|Rodovia|Viela)';

-- Fix "Cond Edifício X - Rua Y" pattern
UPDATE establishments SET complement = SUBSTRING_INDEX(address, ' - Rua', 1), address = CONCAT('Rua', SUBSTRING(address, LOCATE(' - Rua', address) + 5)) WHERE address LIKE '%- Rua %' AND address NOT REGEXP '^(Rua|Avenida|Alameda|Praça|Travessa|Largo|Estrada|Rodovia|Viela)';

-- Fix "R - Rua" typo
UPDATE establishments SET address = CONCAT('Rua', SUBSTRING(address, LOCATE('Rua', address) + 3)) WHERE address LIKE 'R - Rua%';

-- Clear addresses that are just "Bairro, São Paulo - SP, Brasil" (no actual street)
UPDATE establishments SET address = NULL WHERE address REGEXP '^[A-Za-zÀ-ú ]+, São Paulo - SP,? (Brasil|[0-9])' AND address NOT REGEXP '^(Rua|Avenida|Alameda|Praça|Travessa|Largo|Estrada|Rodovia|Viela)';

